scwin.onUdcCompleted = function() {
   ed_qryConDtFm.setValue(scwin.strPreDate);
   ed_qryConDtTo.setValue(scwin.strCurDate);
   ed_sellLodeptCd.focus();

   div_qryConKnd2.hide();
};

